/// Execute a system transaction with explicit gas contribution for receipts.
///
/// For system transactions, the caller determines the gas contribution (e.g., callback gas,
/// calldata gas). This method ensures receipts reflect the correct `gasUsed`.
///
/// The closure receives the execution result and should return the gas to add to
/// cumulative_gas_used for this transaction's receipt.
///
/// Returns `(evm_gas_used, block_gas_contribution)`.
fn execute_system_transaction_with_gas(
    &mut self,
    tx: impl ExecutorTx<Self::Executor>,
    f: impl FnOnce(
        &ExecutionResult<<<Self::Executor as BlockExecutor>::Evm as Evm>::HaltReason>,
    ) -> u64,
) -> Result<(u64, u64), BlockExecutionError>;

fn execute_system_transaction_with_gas(
    &mut self,
    tx: impl ExecutorTx<Self::Executor>,
    f: impl FnOnce(&ExecutionResult<<F::EvmFactory as EvmFactory>::HaltReason>) -> u64,
) -> Result<(u64, u64), BlockExecutionError> {
    let (evm_gas, block_gas) =
        self.executor.execute_system_transaction_with_gas(tx.as_executable(), f)?;
    self.transactions.push(tx.into_recovered());
    Ok((evm_gas, block_gas))
}
